import { NextResponse } from "next/server";
import fs from "fs";
import path from "path";
import os from "os";

function resolveLogPath(agentName: string): string {
  const cleanName = agentName.toLowerCase().trim();
  const candidates = [
    path.join(os.tmpdir(), `agent-${cleanName}.log`),
    path.join("C:", "Users", "USER-NT", "AppData", "Local", "Temp", `agent-${cleanName}.log`),
    path.join("C:", "tmp", `agent-${cleanName}.log`),
    `/tmp/agent-${cleanName}.log`
  ];

  for (const p of candidates) {
    if (fs.existsSync(p)) {
      return p;
    }
  }
  return candidates[0]; // fallback
}

export async function GET(request: Request) {
  try {
    const { searchParams } = new URL(request.url);
    const agent = searchParams.get("agent") || "innova";
    const logPath = resolveLogPath(agent);

    if (!fs.existsSync(logPath)) {
      return NextResponse.json({
        agent,
        exists: false,
        path: logPath,
        lines: [
          `[SYSTEM] Standby - File not found: ${logPath}`,
          `[SYSTEM] tmux session 'innova' might not be running yet.`
        ]
      });
    }

    const content = fs.readFileSync(logPath, "utf-8");
    const rawLines = content.split(/\r?\n/);
    const lines = rawLines
      .filter(line => line.trim().length > 0)
      .slice(-100); // Send last 100 lines

    return NextResponse.json({
      agent,
      exists: true,
      path: logPath,
      lines
    });
  } catch (error: any) {
    return NextResponse.json(
      { error: error.message || "Failed to read logs" },
      { status: 500 }
    );
  }
}

