interface ErrorEvent {
  type: 'error';
  message: string;
  timestamp: number;
}

type SSEEvent =
  | AgentStartedEvent
  | ToolCalledEvent
  | AnswerDeltaEvent
  | AnswerCompleteEvent
  | ErrorEvent;

// ---------------------------------------------------------------------------
// Simple in‑process event hub (singleton)
// ---------------------------------------------------------------------------

class EventHub {
  private listeners = new Set<(event: SSEEvent) => void>();

  /**
   * Register a listener and return a disposal function.
   * Call the returned function to remove the listener.
   */
  addListener(listener: (event: SSEEvent) => void): () => void {
    this.listeners.add(listener);
    return () => {
      this.listeners.delete(listener);
    };
  }

  /** Emit an event to all currently registered listeners. */
  emit(event: SSEEvent): void {
    for (const listener of this.listeners) {
      listener(event);
    }
  }
}

export const eventHub = new EventHub();

